import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

function Nav() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/'); // Redirect to splash page after logout
  };

  return (
    <header>
      <div className="logo">Cead's Pot</div>
      <nav>
        <ul>
          {/* Common links for everyone */}
          <li>
            <NavLink to="/home" className={({ isActive }) => isActive ? 'active' : ''}>
              Home
            </NavLink>
          </li>
          <li>
            <NavLink to="/about" className={({ isActive }) => isActive ? 'active' : ''}>
              About
            </NavLink>
          </li>
          <li>
            <NavLink to="/contact" className={({ isActive }) => isActive ? 'active' : ''}>
              Resources
            </NavLink>
          </li>

          {/* Conditional rendering based on authentication */}
          {!user ? (
            // GUEST - not logged in
            <>
              <li>
                <NavLink to="/register" className={({ isActive }) => isActive ? 'active' : ''}>
                  Sign Up
                </NavLink>
              </li>
              <li>
                <NavLink to="/login" className={({ isActive }) => isActive ? 'active' : ''}>
                  Login
                </NavLink>
              </li>
            </>
          ) : (
            // LOGGED IN USER
            <>
              {/* Common for all logged in users (regular user & admin) */}
              <li>
                <NavLink to="/profile" className={({ isActive }) => isActive ? 'active' : ''}>
                  Profile
                </NavLink>
              </li>
              <li>
                <NavLink to="/create-post" className={({ isActive }) => isActive ? 'active' : ''}>
                  Create Post
                </NavLink>
              </li>
              
              {/* Admin only link */}
              {user.role === 'admin' && (
                <li>
                  <NavLink to="/admin" className={({ isActive }) => isActive ? 'active' : ''}>
                    Admin Page
                  </NavLink>
                </li>
              )}
              
              {/* Logout button */}
              <li>
                <button onClick={handleLogout} className="logout-btn">
                  Log Out
                </button>
              </li>

              {/* Optional: Show username */}
              <li className="username-display">
                <span>Hello, {user.name}!</span>
              </li>
            </>
          )}
        </ul>
      </nav>
    </header>
  );
}

export default Nav;
